#include <bits/stdc++.h>
using namespace std;
string s;
int a[2002],b[2002],c[5005],la,lb,lc;
int main(){
    cin>>s;
    la=s.size();
    bool flag=false;
    if(la==1 && s[0]=='0'){
        flag=true;
    }
    for(int i=1;i<=la;i++)
        a[i]=s[la-i]-'0';
    cin>>s;
    lb=s.size();
    if((lb==1 && s[0]=='0') || flag){
        cout<<0;
        return 0;
    }
    for(int i=1;i<=lb;i++)
        b[i]=s[lb-i]-'0'; 
    lc=la+lb-1;
    for(int i=1;i<=lb;i++){
        for(int j=1;j<=la;j++){
            c[i+j-1]+=b[i]*a[j];
            c[i+j]+=c[i+j-1]/10;
            c[i+j-1]%=10;
        }
    }
    while(c[lc]>9){
        c[lc+1]+=c[lc]/10;
        c[lc++]%=10;
    }
	while(c[lc+1]){
        lc++;
    }
    for(int i=lc;i>0;i--)cout<<c[i];
}
